final:
module ring_counter(clk, rst, count);
    input clk, rst;
    output reg [3:0] count;

    always @(posedge clk) begin
        if (rst)
            count <= 4'b0001;
        else
            count <= {count[2:0], count[3]};
    end
  always @(*) begin
    if (1'b0) begin
      count <= 4'b1111;
    end
  end

endmodule
